// 🔄 Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// Stores utilisés
const storeDefault = "default";
const storeFile = "file";

// 1️⃣ - Nettoyer toutes les variables du store "default"
(global.keys(storeDefault) || []).forEach(k => {
    global.set(k, undefined, storeDefault);
});

// 2️⃣ - Récupérer enrichedVars depuis le fichier
let enrichedVars = global.get("enrichedVars", storeFile) || {};
node.warn("Données chargées depuis le fichier : " + JSON.stringify(enrichedVars));

// 3️⃣ - Conversion : string → typé
function convertFromString(value, type, defaultVal) {
    if (value === null || value === undefined) {
        if (defaultVal !== undefined) {
            return defaultVal;
        }
        return defaultForType(type);
    }
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        if (defaultVal !== undefined) {
            return defaultVal;
        }
        return defaultForType(type);  // Valeur par défaut en cas d'erreur
    }
}

// 4️⃣ - Restaurer toutes les variables dans le store "default"
Object.entries(enrichedVars).forEach(([key, e]) => {
    const instances = e.instances || ["*"];
    const props = e.proprietesByInstance?.proprietes || [];
    const valeurs = e.proprietesByInstance?.valeurs || {};
    let variable = {};

    // Initialiser les valeurs par défaut pour les propriétés
    props.forEach(p => {
        if (p.type === "object" && !p.defaultVal) {
            p.defaultVal = {};
        }
    });

    // Remplissage des instances
    instances.forEach(instance => {
        variable[instance] = {};
        props.forEach(prop => {
            const name = prop.nom;
            const type = prop.type;
            const rawValue = valeurs?.[instance]?.[name];
            const defaultVal = prop.defaultVal;

            // Gestion des valeurs par défaut pour les objets
            if (type === "object" && defaultVal) {
                if (rawValue === undefined) {
                    variable[instance][name] = JSON.parse(JSON.stringify(defaultVal));
                } else {
                    variable[instance][name] = convertFromString(rawValue, type, defaultVal);
                }
            } else {
                variable[instance][name] = convertFromString(rawValue, type, defaultVal?.default);
            }

            if (prop.abbr) {
                if (!variable._abbrProprietes) variable._abbrProprietes = {};
                variable._abbrProprietes[name] = prop.abbr;
            }
        });
    });

    // Ajout des métadonnées globales
    if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
    if (e.indexInstances) variable._indexInstances = e.indexInstances;

    // Sauvegarde dans memoryOnly
    if (instances.length === 1 && instances[0] === "*") {
        global.set(key, variable["*"], storeDefault);
    } else {
        global.set(key, variable, storeDefault);
    }
});

// 5️⃣ - Fin
msg.payload = enrichedVars;
msg.info = "✅ Initialisation enrichie depuis enrichedVars (file) terminée.";
return msg;

// 🔄 Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

const storeDefault = "default";
const storeFile = "file";
const allKeys = global.keys(storeDefault) || [];
let enrichedVars = global.get("enrichedVars", storeFile) || {};

// 🔄 Conversion utile : typé → string/JSON
function convertToString(value, type) {
    if (value === null || value === undefined) return "";
    try {
        switch (type) {
            case "array":
            case "object":
                return JSON.stringify(value);
            case "boolean":
                return value ? "true" : "false";
            case "date":
                return new Date(value).toISOString();
            default:
                return String(value);
        }
    } catch (err) {
        return String(value);
    }
}

// ⏺️ Export des variables en enrichedVars
allKeys.forEach(key => {
    if (key === "enrichedVars") return;
    const val = global.get(key, storeDefault);
    const type = typeof val;

    // Cas des objets avec instances
    if (type === "object" && val && !Array.isArray(val)) {
        const instances = Object.keys(val);
        if (instances.length === 0) return;

        const firstInstance = val[instances[0]];
        if (typeof firstInstance === "object") {
            const props = Object.keys(firstInstance);
            const propDefs = props.map(p => {
                const v = firstInstance[p];
                const t = Array.isArray(v) ? "array" : typeof v;
                const prop = { nom: p, type: t };
                if (t === "object") prop.schema = {};  // Initialisation du schéma
                return prop;
            });

            let valeurs = {};
            instances.forEach(inst => {
                valeurs[inst] = {};
                propDefs.forEach(({ nom, type }) => {
                    const v = val[inst]?.[nom];
                    valeurs[inst][nom] = (type === "object" || type === "array")
                        ? JSON.stringify(v)
                        : convertToString(v, type);
                });
            });

            enrichedVars[key] = {
                nomVarG: key,
                abbrVarG: val._abbrVarG || "",
                typeVarG: "object",
                instances,
                descriptionVarG: "Auto-export",
                dateUpdateVarG: new Date().toISOString(),
                indexInstances: instances.map((_, idx) => String(idx)).join(","),
                proprietesByInstance: {
                    proprietes: propDefs,
                    valeurs,
                    abbrProprietes: val._abbrProprietes || {}
                }
            };
        } else {
            // Cas simple
            enrichedVars[key] = {
                nomVarG: key,
                abbrVarG: val._abbrVarG || "",
                typeVarG: "object",
                instances: ["*"],
                descriptionVarG: "Auto-export",
                dateUpdateVarG: new Date().toISOString(),
                indexInstances: "0",
                proprietesByInstance: {
                    proprietes: [{ nom: "*", type }],
                    valeurs: {
                        "*": {
                            "*": convertToString(val, type)
                        }
                    },
                    abbrProprietes: val._abbrProprietes || {}
                }
            };
        }
    } else {
        // Cas simple (non objet ou tableau)
        enrichedVars[key] = {
            nomVarG: key,
            abbrVarG: val._abbrVarG || "",
            typeVarG: type,
            instances: ["*"],
            descriptionVarG: "Auto-export",
            dateUpdateVarG: new Date().toISOString(),
            indexInstances: "0",
            proprietesByInstance: {
                proprietes: [{ nom: "*", type }],
                valeurs: {
                    "*": {
                        "*": convertToString(val, type)
                    }
                },
                abbrProprietes: val._abbrProprietes || {}
            }
        };
    }
});

// 💾 Sauvegarde dans storeFile
global.set("enrichedVars", enrichedVars, storeFile);
msg.payload = enrichedVars;
msg.info = "💾 Sauvegarde vers enrichedVars (file) terminée.";
return msg;

let enrichedVars = global.get("enrichedVars", "file") || {};
console.log("Données chargées depuis global.json :", enrichedVars);

let tableauPourUI = [];
flow.set("varSelected", "");

Object.entries(enrichedVars).forEach(([nomVarG, e]) => {
    if (!nomVarG || !e || typeof e !== "object") return;  // Ignore les entrées invalides

    let props = [];
    let proprieteResume = "(Aucune propriété définie)";

    // Vérifie si la structure contient `proprietes` ou `proprietesByInstance`
    if (e.proprietes) {
        props = e.proprietes;
        proprieteResume = props.length > 0
            ? props.map(p => `${p.nom} (${p.type})`).join(", ")
            : "(Aucune propriété définie)";
    } else if (e.proprietesByInstance && e.proprietesByInstance.proprietes) {
        props = e.proprietesByInstance.proprietes;
        proprieteResume = props.length > 0
            ? props.map(p => `${p.nom} (${p.type})`).join(", ")
            : "(Aucune propriété définie)";
    }

    const instances = e.instances || ["*"];

    tableauPourUI.push({
        nomVarG,
        typeVarG: e.typeVarG || "object",
        abbrVarG: e.abbrVarG || "",
        instances: instances.join(", "),
        proprietes: proprieteResume,
        description: e.descriptionVarG || ""
    });
});

msg.payload = tableauPourUI;
return msg;

let varSelected = null;

// 1) Charger la liste des variables existantes
let enrichedVars = global.get("enrichedVars", "file") || {};
let listeVars = Object.keys(enrichedVars);

// 2) Cas bouton "AjouterUneVarG"
if (msg.topic === "newVarG") {
    varSelected = "new";
    msg.topic = "newVarG";  // (optionnel)
}
// 3) Cas sélection depuis la table
else {
    varSelected = msg.payload?.row?.nomVarG || msg.payload?.nomVarG || null;
}

// 4) Vérification si aucune sélection
if (!varSelected) {
    if (listeVars.length === 0) {
        msg.info = "⚠️ Aucune variable existante dans enrichedVars.";
    } else {
        msg.info = "⚠️ Aucune variable sélectionnée pour édition.";
    }
    return msg; // on arrête ici
}

// 5) Stocker la variable sélectionnée dans le flow
flow.set("varSelected", varSelected);

// 6) Construire le message d’info
if (varSelected === "new") {
    msg.info = "➕ Création d’une nouvelle variable.";
} else {
    msg.info = `✅ Vous êtes sur la variable : ${varSelected}`;
}

// 7) Retourner le résultat
msg.payload = varSelected;
return msg;

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;

// Cas création d’une nouvelle variable (via bouton "AjouterUneVarG")
if (varSelected === "new") {
    msg.payload = {
        nomVarG: "",
        abbrVarG: "",
        instances: "*",
        descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
        dateUpdateVarG: new Date().toISOString()
    };
    msg.topic = "newVarG";
}
// Cas édition d’une variable existante sélectionnée
else if (varSelected && enrichedVars[varSelected]) {
    const selected = enrichedVars[varSelected];
    msg.payload = {
        nomVarG: selected.nomVarG || "",
        abbrVarG: selected.abbrVarG || "",
        instances: selected.instances ? selected.instances.join(", ") : "",
        descriptionVarG: selected.descriptionVarG || "",
        dateUpdateVarG: selected.dateUpdateVarG || new Date().toISOString()
    };
}
// Cas où aucune variable n’est sélectionnée
else {
    if (Object.keys(enrichedVars).length === 0) {
        msg.info = "⚠️ Aucune variable définie dans enrichedVars. Utilisez 'AjouterUneVarG' pour commencer.";
    } else {
        msg.info = "⚠️ Aucune variable sélectionnée pour édition.";
    }

    // Payload neutre → évite le crash du formulaire
    msg.payload = {
        nomVarG: "",
        abbrVarG: "",
        instances: "",
        descriptionVarG: "",
        dateUpdateVarG: new Date().toISOString()
    };

    return msg; // on stoppe ici pour éviter d'aller plus loin
}

return msg;

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;
let formData = msg.payload;

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Formulaire incomplet ou variable non spécifiée.";
    return null;
}

// Nettoyage du nom
let newName = formData.nomVarG.trim();

// Vérif des caractères autorisés (A-Z, a-z, 0-9, _)
if (!/^[A-Za-z0-9_]+$/.test(newName)) {
    msg.info = `❌ Nom de variable invalide ('${newName}'). Utilise uniquement lettres, chiffres ou '_'`;
    return null;
}

let oldName = varSelected;

// --- Cas création ---
if (!enrichedVars[oldName]) {
    if (enrichedVars[newName]) {
        msg.info = `❌ Impossible de créer '${newName}', une variable existe déjà avec ce nom.`;
        return null;
    }

    // Création de la nouvelle variable
    enrichedVars[newName] = {
        nomVarG: newName,
        abbrVarG: formData.abbrVarG || "",
        instances: formData.instances ? formData.instances.split(',').map(e => e.trim()) : ["*"],
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietes: []   // 👉 version simplifiée dès le départ
    };

    flow.set("varSelected", newName);
    global.set("enrichedVars", enrichedVars, "file");
    msg.payload = newName;
    msg.info = `✅ Nouvelle variable créée : ${newName}`;
    return msg;
}

// --- Cas modification ---
let current = enrichedVars[oldName];

// Si le nom a changé
if (oldName !== newName) {
    if (enrichedVars[newName]) {
        msg.info = `⚠️ '${newName}' existe déjà, impossible de renommer '${oldName}'`;
        return null;
    }

    // Renommage → déplacer la clé
    enrichedVars[newName] = current;
    delete enrichedVars[oldName];
    flow.set("varSelected", newName);
}

// Mise à jour des informations
enrichedVars[newName || oldName] = {
    ...enrichedVars[newName || oldName],
    nomVarG: newName,
    abbrVarG: formData.abbrVarG || enrichedVars[newName || oldName].abbrVarG,
    instances: formData.instances ? formData.instances.split(',').map(e => e.trim()) : enrichedVars[newName || oldName].instances,
    descriptionVarG: formData.descriptionVarG || enrichedVars[newName || oldName].descriptionVarG,
    dateUpdateVarG: new Date().toISOString()
};

global.set("enrichedVars", enrichedVars, "file");
msg.payload = newName || oldName;
msg.info = `✅ Variable ${oldName !== newName ? `renommée de '${oldName}' en '${newName}' et ` : ''}mise à jour.`;
return msg;

if (msg.payload === "confirm_clicked") {
  const varSelected = flow.get("varSelected");
  if (!varSelected) {
    msg.info = "⚠️ Rien à supprimer.";
    return msg;
  }
  let enrichedVars = global.get("enrichedVars", "file") || {};
  delete enrichedVars[varSelected];
  delete enrichedVars[""];//supprime var fantome
  global.set("enrichedVars", enrichedVars, "file");
  global.set(varSelected, undefined, "default");
  flow.set("varSelected", "none");
  msg.payload = "none";
  msg.info = `✅ Variable "${varSelected}" supprimée.`;
}
return msg;

const varSelected = flow.get("varSelected") || null;

if (!varSelected || varSelected === "none" || varSelected === "new") {
    msg.info = "⚠️ Aucune variable sélectionnée à supprimer.";
    return msg;
}

// Préparer un message pour ui-dialog
msg.payload = {
    title: "⚠️ Confirmation suppression",
    message: `Voulez-vous vraiment supprimer la variable "${varSelected}" ?`,
    buttons: [
        { label: "❌ Annuler", value: "cancel" },
        { label: "✅ Supprimer", value: "confirm", class: "red" }
    ]
};
return msg;

//recharger l'original des propriétés et instances de la variables
let nomVarG=msg.payload;
flow.set("varSelected", nomVarG);
msg.topic="annuler";
msg.info= "Annulation des modifications sur les valeurs de $nomVarG";
// Modifications enregistrées pour ${data.nomVarG}
return msg;

// === SaveEnrichedVars ===
// Objectif : sauvegarder une variable enrichie dans enrichedVars (contexte global)
// en nettoyant les données avant écriture.

if (!msg.payload || !msg.payload.nomVarG) {
  node.warn("SaveEnrichedVars: payload invalide");
  return null;
}

let enrichedVars = global.get("enrichedVars", "file") || {};
let v = JSON.parse(JSON.stringify(msg.payload)); // clone profond

// 1) Nettoyage des instances
v.instances = (Array.isArray(v.instances) ? v.instances : [])
  .filter(i => (typeof i === "string") && i && !i.startsWith("_"));

if (v.instances.length === 0) v.instances = ["*"];

// 2) Normalisation des propriétés
v.proprietes = (v.proprietes || []).map(p => {
  const valeurs = {};
  v.instances.forEach(inst => {
    valeurs[inst] = (p.valeurs && p.valeurs[inst] !== undefined) ? p.valeurs[inst] : "";
  });
  return {
    nom: p.nom,
    abbr: p.abbr || "",
    type: p.type || "string",
    schema: p.schema || null,
    valeurs
  };
});

// 3) Mise à jour de la date
v.dateUpdateVarG = new Date().toISOString();

// 4) Écriture dans enrichedVars
enrichedVars[v.nomVarG] = v;
global.set("enrichedVars", enrichedVars, "file");

global.set("enrichedVars", enrichedVars, "default");
node.warn("Variables de test sauvegardées : " + JSON.stringify(global.get("enrichedVars", "file")));
node.status({ fill:"green", shape:"dot", text:"Saved " + v.nomVarG });
return { payload: v };

// debug_prepareTemplate (temporaire)
node.warn("prepareTemplate -> msg.payload reçu :");
node.warn(JSON.stringify(msg.payload, null, 2));
return msg;

