// Objectif : transformer la variable enrichie stockée en contexte
// en une structure cohérente et nettoyée pour le template d’édition.

let varName = flow.get("varSelected") || msg.payload || null;
if (!varName) {
    node.warn("prepareTemplate: aucune variable sélectionnée !");
    msg.payload = null;
    return msg;
}

let enrichedVars = global.get("enrichedVars", "file") || {};
let variable = enrichedVars[varName];

// Cas variable non trouvée
if (!variable) {
    msg.payload = null;
    msg.info = "❌ Variable non trouvée";
    return msg;
}

// Helpers
function defaultForType(t) {
    switch (t) {
        case "boolean": return false;
        case "int":
        case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// 1) Construire la liste des instances
let instances = Array.isArray(variable.instances) && variable.instances.length > 0
    ? variable.instances.filter(i => (typeof i === "string") && i && !i.startsWith("_"))
    : ["*"];

// 2) Construire les propriétés
let proprietes = [];

// Vérifie si la variable a des propriétés
if (variable.proprietes) {
    proprietes = variable.proprietes.map(p => {
        const type = p.type || "string";
        const valeurs = {};
        instances.forEach(inst => {
            valeurs[inst] = p.valeurs && p.valeurs[inst] !== undefined ? p.valeurs[inst] : defaultForType(type);
        });
        return {
            nom: p.nom || "",
            abbr: p.abbr || "",
            type: type,
            valeurs: valeurs
        };
    });
} else if (variable.proprietesByInstance && variable.proprietesByInstance.proprietes) {
    proprietes = variable.proprietesByInstance.proprietes.map(p => {
        const type = p.type || "string";
        const valeurs = {};
        instances.forEach(inst => {
            valeurs[inst] = p.valeurs && p.valeurs[inst] !== undefined ? p.valeurs[inst] : defaultForType(type);
        });
        return {
            nom: p.nom || "",
            abbr: p.abbr || "",
            type: type,
            valeurs: valeurs
        };
    });
} else {
    node.warn(`Aucune propriété définie pour la variable ${varName}, tableau vide initialisé.`);
}

// 3) Préparer le payload final
msg.payload = {
    nomVarG: variable.nomVarG || varName,
    abbrVarG: variable.abbrVarG || "",
    instances: instances,
    proprietes: proprietes,
    descriptionVarG: variable.descriptionVarG || "",
    dateUpdateVarG: variable.dateUpdateVarG || new Date().toISOString()
};

// Ajouter les informations pour une nouvelle propriété
msg.newProp = {
    nom: "",
    abbr: "",
    type: "",
    initialValues: {}
};
instances.forEach(i => {
    msg.newProp.initialValues[i] = "";
});

msg.info = "✅ prepareTemplate terminé";
return msg;

let enrichedVars = global.get("enrichedVars", "file") || {};
// Verification provisoire
console.log("Données chargées depuis global.json :", enrichedVars);

let tableauPourUI = [];
flow.set("varSelected", "");

Object.entries(enrichedVars).forEach(([nomVarG, e]) => {
    if (!nomVarG || !e || typeof e !== "object") return;  // Ignore les entrées invalides
    if (!e.proprietesByInstance) return; // Ignore les objets incomplets

    const props = e.proprietesByInstance?.proprietes || [];
    const proprieteResume = props.length > 0
        ? props.map(p => `${p.nom} (${p.type})`).join(", ")
        : "(Aucune propriété définie)";

    const instances = e.instances || ["*"];

    tableauPourUI.push({
        nomVarG,
        abbrVarG: e.abbrVarG || "",
        instances: instances.join(", "),
        proprietes: proprieteResume,
        description: e.descriptionVarG || ""
    });
});

msg.payload = tableauPourUI;
return msg;

// === prepareTemplate ===
// Objectif : transformer la variable enrichie stockée en contexte
// en une structure cohérente et nettoyée pour le template d’édition.
//
// Entrée : flow.get("varSelected")
// Sortie : msg.payload = { nomVarG, abbrVarG, instances, proprietes, descriptionVarG, dateUpdateVarG }

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;

// Cas création d’une nouvelle variable
if (varSelected === "new") {
    msg.payload = {
        nomVarG: "",
        abbrVarG: "",
        instances: ["*"],            // toujours au moins une instance
        proprietes: [],              // vide au départ
        descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
        dateUpdateVarG: new Date().toISOString()
    };
    msg.info = "➕ Nouvelle variable à définir.";
    return msg;
}

// Cas aucune variable sélectionnée
if (!varSelected || !enrichedVars[varSelected]) {
    if (Object.keys(enrichedVars).length === 0) {
        msg.info = "⚠️ Aucune variable définie dans enrichedVars.";
    } else {
        msg.info = "⚠️ Aucune variable sélectionnée pour édition.";
    }
    msg.payload = null; // évite de polluer l’UI
    return msg;
}

// Cas édition d’une variable existante
let variable = enrichedVars[varSelected];

// Helpers
function defaultForType(t) {
    switch(t) {
        case "boolean": return false;
        case "int":
        case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0,10);
        default: return "";
    }
}
function convertFromString(value, type) {
    if (value === null || value === undefined) return defaultForType(type);
    try {
        switch(type) {
            case "int": return parseInt(value,10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch(e) {
        return defaultForType(type);
    }
}

// Construire la liste des instances
let instances = Array.isArray(variable.instances) 
    ? variable.instances.filter(i => typeof i === "string" && i && !i.startsWith("_"))
    : [];

if (instances.length === 0) instances = ["*"];

// Construire les propriétés
let proprietes = [];
if (Array.isArray(variable.proprietes) && variable.proprietes.length > 0) {
    proprietes = variable.proprietes.map(p => {
        const type = p.type || "string";
        const schema = p.schema || (type === "object" || type === "array" ? {} : null);
        const valeurs = {};
        instances.forEach(inst => {
            const raw = (p.valeurs && p.valeurs[inst] !== undefined) ? p.valeurs[inst] : undefined;
            valeurs[inst] = convertFromString(raw, type);
        });
        return {
            nom: p.nom || "",
            abbr: p.abbr || "",
            type,
            schema,
            valeurs
        };
    });
}

// Payload final
msg.payload = {
    nomVarG: variable.nomVarG || varSelected,
    abbrVarG: variable.abbrVarG || "",
    instances,
    proprietes,
    descriptionVarG: variable.descriptionVarG || "",
    dateUpdateVarG: variable.dateUpdateVarG || new Date().toISOString()
};

msg.info = `✅ Variable chargée : ${varSelected}`;
return msg;
